/* ===========================================================================
 * Search input — accessible name (WCAG 1.3.1 Info and Relationships,
 *                              4.1.2 Name, Role, Value)
 *
 * Background (the bug these tests guard against): the toolbar search input
 * was created with only `type="text"` and `placeholder="Search..."` and NO
 * programmatically determinable accessible name — no `aria-label` and no
 * associated <label>. A placeholder is NOT an accessible name: it is a
 * last-resort, low-contrast hint that vanishes the moment the user types, and
 * the accessible-name computation only falls back to it when nothing else is
 * present, making it fragile and unreliable for screen-reader users (who got
 * either no name or a fragile one). Notably the upload input right next to it
 * correctly exposes `aria-label="Upload files"`, so this was an inconsistency.
 *
 * The fix adds `aria-label="Search files"` to the search input. The
 * .search-wrapper holds no visible <label> text, so aria-label is the right
 * mechanism (matching the upload input) rather than a <label> association.
 * The placeholder is KEPT — it doubles as the empty-state hint for sighted
 * users and drives the `:placeholder-shown` clear-button toggle — so these
 * tests also pin that the aria-label does not displace the placeholder.
 *
 * happy-dom does not run the full accessible-name computation, so these tests
 * assert against the content attribute itself (the mechanism that produces a
 * correct accessible name in a real browser) rather than the computed name.
 * ========================================================================= */
describe('search input — accessible name', () => {
  describe('the search input exposes a programmatic accessible name', () => {
    it('sets aria-label="Search files"', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
    });

    it('the aria-label is a non-empty, non-whitespace string', () => {
      // Guards against a regression that sets aria-label="" or "   ", which is
      // worse than no label: an empty accessible name can override a
      // placeholder-derived name in the name computation, yielding a control
      // with NO accessible name at all.
      const { searchInput } = setup();
      const label = searchInput.getAttribute('aria-label') ?? '';
      expect(label.length).toBeGreaterThan(0);
      expect(label.trim().length).toBeGreaterThan(0);
    });

    it('does not also set aria-hidden (which would exclude it from the a11y tree)', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('aria-hidden')).toBeNull();
    });
  });

  describe('the placeholder is retained (not replaced by the aria-label)', () => {
    it('still carries placeholder="Search..." for sighted users', () => {
      // The placeholder doubles as the empty-state hint AND drives the
      // `:placeholder-shown` clear-button toggle (see search-wrapper.test.ts),
      // so adding the aria-label must not remove it.
      const { searchInput } = setup();
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
    });

    it('still has type="text" (the control type is unchanged)', () => {
      const { searchInput } = setup();
      expect(searchInput.type).toBe('text');
    });
  });

  /* Consistency check: the search input now follows the SAME accessible-name
     pattern as its sibling upload control (aria-label set via setAttribute,
     matching a visible control whose affordance has no wrapping <label>). */
  describe('consistency with the upload input', () => {
    it('the search and upload inputs each expose an aria-label', () => {
      const { searchInput, uploadInput } = setup();
      expect(searchInput.hasAttribute('aria-label')).toBe(true);
      expect(uploadInput.hasAttribute('aria-label')).toBe(true);
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
      expect(uploadInput.getAttribute('aria-label')).toBe('Upload files');
    });
  });
});

